// Response safety classifier
class ResponseSafetyFilter {
  constructor() {
    this.sensitivePatterns = [
      /api[_-]?key\s*[:=]/i,
      /password\s*[:=]/i,
      /secret\s*[:=]/i,
      /bearer\s+[a-zA-Z0-9\-_.]+/i,
      /-----BEGIN\s+(RSA\s+)?PRIVATE\s+KEY-----/,
      /mongodb(\+srv)?:\/\//i,
      /postgres:\/\//i
    ];

    this.piiPatterns = [
      /\b\d{3}-\d{2}-\d{4}\b/, // SSN
      /\b\d{16}\b/, // Credit card
      /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/ // Email
    ];
  }

  filterResponse(response, context) {
    const result = {
      safe: true,
      filtered: response,
      redactions: []
    };

    // Check for sensitive data leaks
    for (const pattern of this.sensitivePatterns) {
      if (pattern.test(response)) {
        result.safe = false;
        result.redactions.push({ type: 'sensitive_data', pattern: pattern.toString() });
      }
    }

    // Check for PII leakage
    for (const pattern of this.piiPatterns) {
      const match = response.match(pattern);
      if (match) {
        result.filtered = result.filtered.replace(pattern, '[REDACTED]');
        result.redactions.push({ type: 'pii', matched: match[0].substring(0, 4) + '...' });
      }
    }

    // Check for role confusion indicators
    if (/I\s+am\s+(now|no\s+longer)\s+a/i.test(response)) {
      result.safe = false;
      result.redactions.push({ type: 'role_confusion' });
    }

    return result;
  }
}

