class MLSecurityService {
  constructor(model) {
    this.model = model;
    this.temperatureCalibration = 1.5;  // Softens overconfident predictions
  }

  // Temperature scaling to reduce membership inference vulnerability
  // Overconfident predictions leak training membership
  applyTemperatureScaling(logits, temperature = this.temperatureCalibration) {
    return logits.map(l => l / temperature);
  }

  // Softmax with temperature
  softmaxWithTemperature(logits, temperature) {
    const scaled = this.applyTemperatureScaling(logits, temperature);
    const maxLogit = Math.max(...scaled);
    const exps = scaled.map(l => Math.exp(l - maxLogit));
    const sumExps = exps.reduce((a, b) => a + b, 0);
    return exps.map(e => e / sumExps);
  }

  // Label smoothing defense - reduces confidence gap between members/non-members
  applyLabelSmoothing(probabilities, smoothingFactor = 0.1) {
    const numClasses = probabilities.length;
    const uniform = 1.0 / numClasses;
    return probabilities.map(p => 
      (1 - smoothingFactor) * p + smoothingFactor * uniform
    );
  }

  // Differential privacy noise calibrated to sensitivity
  addCalibratedNoise(value, sensitivity = 0.01, epsilon = 1.0) {
    // Laplace mechanism for differential privacy
    const scale = sensitivity / epsilon;
    const u = Math.random() - 0.5;
    const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
    return Math.max(0, Math.min(1, value + noise));
  }

  // Prediction with all privacy defenses
  async securePrediction(inputTensor) {
    // Get raw model output (logits before softmax)
    const logits = await this.model.predict(inputTensor).array();

    // Apply temperature scaling
    const calibratedProbs = this.softmaxWithTemperature(
      logits[0], 
      this.temperatureCalibration
    );

    // Apply label smoothing
    const smoothedProbs = this.applyLabelSmoothing(calibratedProbs);

    // Add differential privacy noise
    const privatizedProbs = smoothedProbs.map(p => 
      this.addCalibratedNoise(p)
    );

    return privatizedProbs;
  }
}

class QueryAnomalyDetector {
  constructor(redisClient) {
    this.redis = redisClient;
    this.WINDOW_SIZE = 3600;  // 1 hour window
    this.EXTRACTION_THRESHOLD = 100;
    this.MEMBERSHIP_THRESHOLD = 50;
  }

  async trackQuery(apiKey, queryFingerprint, queryType) {
    const key = `ml:queries:${apiKey}`;
    const now = Date.now();

    // Store query with fingerprint and timestamp
    await this.redis.zAdd(key, {
      score: now,
      value: JSON.stringify({ fingerprint: queryFingerprint, type: queryType, ts: now })
    });

    // Remove queries outside window
    await this.redis.zRemRangeByScore(key, 0, now - this.WINDOW_SIZE * 1000);

    // Set expiry
    await this.redis.expire(key, this.WINDOW_SIZE * 2);
  }

  async detectAnomalies(apiKey) {
    const key = `ml:queries:${apiKey}`;
    const queries = await this.redis.zRange(key, 0, -1);

    const parsed = queries.map(q => JSON.parse(q));
    const uniqueFingerprints = new Set(parsed.map(q => q.fingerprint));

    const anomalies = {
      possibleExtraction: uniqueFingerprints.size > this.EXTRACTION_THRESHOLD,
      possibleMembershipInference: this.detectMembershipPattern(parsed),
      queryVelocity: queries.length,
      uniqueQueries: uniqueFingerprints.size
    };

    return anomalies;
  }

  // Detect membership inference attack patterns
  // These attacks often query with slight variations of same image
  detectMembershipPattern(queries) {
    if (queries.length < 10) return false;

    // Check for repeated queries (same fingerprint) - MI attack signal
    const fingerprintCounts = {};
    queries.forEach(q => {
      fingerprintCounts[q.fingerprint] = (fingerprintCounts[q.fingerprint] || 0) + 1;
    });

    const repeatedQueries = Object.values(fingerprintCounts)
      .filter(count => count > 3).length;

    return repeatedQueries > this.MEMBERSHIP_THRESHOLD / 10;
  }
}

class ResponseSanitizer {
  // Quantize confidence to prevent fine-grained inference
  static quantizeConfidence(confidence, levels = 5) {
    const step = 1.0 / levels;
    return Math.round(confidence / step) * step;
  }

  // Cap maximum confidence to reduce membership inference signal
  static capConfidence(confidence, maxConfidence = 0.95) {
    return Math.min(confidence, maxConfidence);
  }

  // Create sanitized response
  static sanitize(probabilities, options = {}) {
    const {
      topK = 3,
      quantizeLevels = 10,
      maxConfidence = 0.95,
      includeOther = true
    } = options;

    const indexed = probabilities.map((p, i) => ({ prob: p, index: i }));
    indexed.sort((a, b) => b.prob - a.prob);

    const topPredictions = indexed.slice(0, topK).map(item => ({
      class: item.index,
      confidence: this.quantizeConfidence(
        this.capConfidence(item.prob, maxConfidence),
        quantizeLevels
      )
    }));

    // Aggregate remaining probability to hide distribution tail
    if (includeOther && topK < probabilities.length) {
      const otherProb = indexed.slice(topK)
        .reduce((sum, item) => sum + item.prob, 0);
      topPredictions.push({
        class: 'other',
        confidence: this.quantizeConfidence(otherProb, quantizeLevels)
      });
    }

    return topPredictions;
  }
}

