      'gradient_estimation', // Numerical gradient approximation
      'membership_inference' // Training data extraction
    ];
  }

  async analyzeQuery(apiKey, input, timestamp) {
    const historyKey = `query_history:${apiKey}`;
    const anomalyKey = `anomaly_score:${apiKey}`;

    // Store query with timestamp
    await this.redis.lpush(historyKey, JSON.stringify({ input, timestamp }));
    await this.redis.ltrim(historyKey, 0, 999); // Keep last 1000
    await this.redis.expire(historyKey, 86400); // 24 hour TTL

    const history = await this.redis.lrange(historyKey, 0, -1);
    const queries = history.map(h => JSON.parse(h));

    const analysis = {
      gridSearchScore: this.detectGridSearch(queries),
      boundaryProbingScore: this.detectBoundaryProbing(queries),
      gradientEstimationScore: this.detectGradientEstimation(queries),
      temporalAnomalyScore: this.detectTemporalAnomaly(queries)
    };

    const totalScore = Object.values(analysis).reduce((a, b) => a + b, 0) / 4;

    // Update rolling anomaly score
    await this.redis.set(anomalyKey, totalScore, 'EX', 3600);

    return { score: totalScore, details: analysis };
  }

  detectGridSearch(queries) {
    if (queries.length < 50) return 0;

    // Check if inputs form a regular grid pattern
    const inputs = queries.map(q => q.input);
    const dimensions = inputs[0].length;

    let gridScore = 0;
    for (let d = 0; d < Math.min(dimensions, 10); d++) {
      const values = inputs.map(i => i[d]).sort((a, b) => a - b);
      const diffs = values.slice(1).map((v, i) => v - values[i]);
      const variance = this.variance(diffs);
      if (variance < 0.01) gridScore += 0.1; // Regular spacing detected
    }

    return Math.min(1, gridScore);
  }

  detectBoundaryProbing(queries) {
    if (queries.length < 30) return 0;

    // Detect pairs of very similar inputs (probing decision boundaries)
    const inputs = queries.map(q => q.input);
    let closeCount = 0;

    for (let i = 0; i < Math.min(inputs.length, 100); i++) {
      for (let j = i + 1; j < Math.min(inputs.length, 100); j++) {
        const dist = this.euclideanDistance(inputs[i], inputs[j]);
        if (dist < 0.01) closeCount++; // Very close inputs
      }
    }

    return Math.min(1, closeCount / 50);
  }

  detectGradientEstimation(queries) {
    if (queries.length < 20) return 0;

    // Detect finite-difference patterns (x, x+ε, x-ε)
    const inputs = queries.map(q => q.input);
    let patternCount = 0;

    for (let i = 0; i < inputs.length - 2; i++) {
      const diff1 = this.vectorSubtract(inputs[i + 1], inputs[i]);
      const diff2 = this.vectorSubtract(inputs[i + 2], inputs[i + 1]);

      // Check if diff2 ≈ -diff1 (finite difference pattern)
      const sum = this.vectorAdd(diff1, diff2);
      if (this.vectorNorm(sum) < 0.001) patternCount++;
    }

    return Math.min(1, patternCount / 10);
  }

  detectTemporalAnomaly(queries) {
    if (queries.length < 10) return 0;

    // Check for unnaturally regular timing (bot behavior)
    const timestamps = queries.map(q => q.timestamp);
    const intervals = timestamps.slice(1).map((t, i) => t - timestamps[i]);
    const variance = this.variance(intervals);

    // Very low variance = likely automated
    if (variance < 100) return 0.8;
    if (variance < 1000) return 0.4;
    return 0;
  }

  // Utility functions
  variance(arr) {
    const mean = arr.reduce((a, b) => a + b, 0) / arr.length;
    return arr.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / arr.length;
  }

  euclideanDistance(a, b) {
    return Math.sqrt(a.reduce((sum, val, i) => sum + Math.pow(val - b[i], 2), 0));
  }

  vectorSubtract(a, b) { return a.map((v, i) => v - b[i]); }
  vectorAdd(a, b) { return a.map((v, i) => v + b[i]); }
  vectorNorm(v) { return Math.sqrt(v.reduce((sum, val) => sum + val * val, 0)); }
}

// Adaptive response degradation based on risk score
class AdaptiveDefense {
  constructor() {
    this.defenseStrategies = {
      low: { noise: 0.02, topK: 5, delay: 0 },
      medium: { noise: 0.1, topK: 3, delay: 100 },
      high: { noise: 0.2, topK: 1, delay: 500 },
      critical: { noise: 0.5, topK: 1, delay: 2000, degraded: true }
    };
  }

  getStrategy(anomalyScore) {
    if (anomalyScore > 0.8) return this.defenseStrategies.critical;
    if (anomalyScore > 0.5) return this.defenseStrategies.high;
    if (anomalyScore > 0.3) return this.defenseStrategies.medium;
    return this.defenseStrategies.low;
  }

  applyDefense(probabilities, strategy) {
    // Add noise
    let defended = probabilities.map(p => {
      const noise = (Math.random() - 0.5) * strategy.noise;
      return Math.max(0, Math.min(1, p + noise));
    });

    // Top-K truncation
    const indexed = defended.map((p, i) => ({ prob: p, class: i }));
    indexed.sort((a, b) => b.prob - a.prob);

    // Normalize top-K
    const topK = indexed.slice(0, strategy.topK);
    const sum = topK.reduce((s, p) => s + p.prob, 0);

    return topK.map(p => ({
      class: p.class,
      confidence: Math.round((p.prob / sum) * 100) / 100
    }));
  }
}

const watermark = new ModelWatermark(process.env.WATERMARK_SECRET);
const queryAnalyzer = new QueryAnalyzer(redis);
const adaptiveDefense = new AdaptiveDefense();

// Main prediction endpoint with full protection
app.post('/api/v2/predict', async (req, res) => {
  const startTime = Date.now();
  const apiKey = req.headers['x-api-key'];
  const requestId = crypto.randomUUID();

  if (!apiKey || !await validateApiKey(apiKey)) {
    return res.status(401).json({ error: 'Invalid API key', requestId });
  }

  // Multi-tier rate limiting
  try {
    await Promise.all([
      rateLimiters.perSecond.consume(apiKey),
      rateLimiters.perMinute.consume(apiKey),
      rateLimiters.perHour.consume(apiKey),
      rateLimiters.perDay.consume(apiKey)
    ]);
  } catch (rateLimitError) {
    await logSecurityEvent({
      type: 'rate_limit_exceeded',
      apiKey,
      requestId,
      tier: rateLimitError.msBeforeNext ? 'short' : 'long'
    });
    return res.status(429).json({
      error: 'Rate limit exceeded',
      retryAfter: Math.ceil(rateLimitError.msBeforeNext / 1000),
      requestId
    });
  }

  const { input } = req.body;

  // Input validation
  if (!Array.isArray(input) || input.length !== 64) {
    return res.status(400).json({ error: 'Invalid input format', requestId });
  }

  // Analyze query for extraction patterns
  const analysis = await queryAnalyzer.analyzeQuery(apiKey, input, Date.now());
  const strategy = adaptiveDefense.getStrategy(analysis.score);

  // Log high-risk queries
  if (analysis.score > 0.5) {
    await logSecurityEvent({
      type: 'extraction_attempt_suspected',
      apiKey,
      requestId,
      anomalyScore: analysis.score,
      details: analysis.details,
      strategy: strategy
    });
  }

  // Apply artificial delay for suspicious requests
  if (strategy.delay > 0) {
    await new Promise(resolve => setTimeout(resolve, strategy.delay));
  }

  // Return degraded response for critical risk
  if (strategy.degraded) {
    return res.json({
      predictions: [{ class: 'processing_error', confidence: 0.0 }],
      requestId,
      latency: Date.now() - startTime
    });
  }

  // Run prediction
  const inputTensor = tf.tensor2d([input]);
  const prediction = model.predict(inputTensor);
  const probabilities = (await prediction.array())[0];

  // Apply adaptive defenses
  const defendedPredictions = adaptiveDefense.applyDefense(probabilities, strategy);

  // Audit log
  await logPrediction({
    requestId,
    apiKey,
    timestamp: new Date().toISOString(),
    anomalyScore: analysis.score,
    defenseLevel: Object.keys(adaptiveDefense.defenseStrategies)
      .find(k => adaptiveDefense.defenseStrategies[k] === strategy),
    latency: Date.now() - startTime
  });

  res.json({
    predictions: defendedPredictions.map(p => ({
      class: getClassName(p.class),
      confidence: p.confidence
    })),
    requestId,
    latency: Date.now() - startTime
  });
});

async function logSecurityEvent(event) {
  console.log(JSON.stringify({ ...event, timestamp: new Date().toISOString() }));
  await redis.lpush('security_events', JSON.stringify(event));
}

async function logPrediction(log) {
  await redis.lpush('prediction_logs', JSON.stringify(log));
}

async function validateApiKey(apiKey) {
  return await redis.sismember('valid_api_keys', apiKey);
}

function getClassName(index) {
  const classes = ['cat', 'dog', 'bird', 'fish', 'rabbit', 'hamster', 'turtle', 'snake', 'lizard', 'frog'];
  return classes[index] || 'unknown';
}

